import { useState } from "react";
import { useTranslation } from "react-i18next";
import { useAuth } from "@/contexts/AuthContext";
import { supabase } from "@/integrations/supabase/client";
import { useMerchantRestaurants } from "@/hooks/useActivityParticipation";
import { useLocalizedContent } from "@/hooks/useLocalizedContent";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";
import { Switch } from "@/components/ui/switch";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { toast } from "sonner";
import { Megaphone, Upload, Globe, MapPin, Clock, CheckCircle, XCircle, Loader2, Send, Eye, Gift, Info, ExternalLink } from "lucide-react";

const COUNTRY_OPTIONS = [
  { code: "PT", label: "🇵🇹 Portugal" },
  { code: "ES", label: "🇪🇸 Spain" },
  { code: "FR", label: "🇫🇷 France" },
  { code: "DE", label: "🇩🇪 Germany" },
  { code: "IT", label: "🇮🇹 Italy" },
  { code: "GB", label: "🇬🇧 United Kingdom" },
  { code: "NL", label: "🇳🇱 Netherlands" },
  { code: "CN", label: "🇨🇳 China" },
  { code: "JP", label: "🇯🇵 Japan" },
  { code: "KR", label: "🇰🇷 South Korea" },
  { code: "US", label: "🇺🇸 United States" },
  { code: "BR", label: "🇧🇷 Brazil" },
  { code: "MO", label: "🇲🇴 Macau" },
  { code: "HK", label: "🇭🇰 Hong Kong" },
];

const MerchantAdRequest = () => {
  const { t } = useTranslation();
  const { user } = useAuth();
  const queryClient = useQueryClient();

  // Form state
  const [adName, setAdName] = useState("");
  const [adDescription, setAdDescription] = useState("");
  const [imageUrl, setImageUrl] = useState("");
  const [linkType, setLinkType] = useState<"external" | "restaurant">("external");
  const [linkUrl, setLinkUrl] = useState("");
  const [selectedRestaurantId, setSelectedRestaurantId] = useState<string>("");
  const { data: myRestaurants = [] } = useMerchantRestaurants();
  const { localizeRestaurant } = useLocalizedContent();
  const [globalEnabled, setGlobalEnabled] = useState(false);
  const [selectedCountries, setSelectedCountries] = useState<string[]>([]);
  const [desiredStartDate, setDesiredStartDate] = useState("");
  const [desiredDuration, setDesiredDuration] = useState(1);
  const [notes, setNotes] = useState("");
  const [isUploading, setIsUploading] = useState(false);

  // Fetch user's ad requests
  const { data: myRequests = [], isLoading } = useQuery({
    queryKey: ["my-ad-requests", user?.id],
    queryFn: async () => {
      if (!user) return [];
      const { data, error } = await supabase
        .from("ad_requests" as any)
        .select("*")
        .eq("user_id", user.id)
        .order("created_at", { ascending: false });
      if (error) throw error;
      return data as any[];
    },
    enabled: !!user,
  });

  const submitRequest = useMutation({
    mutationFn: async () => {
      if (!user) throw new Error("Not authenticated");
      if (!adName.trim()) throw new Error("Ad name required");
      if (!imageUrl) throw new Error("Image required");

      const { error } = await supabase.from("ad_requests" as any).insert({
        user_id: user.id,
        ad_name: adName.trim(),
        description: adDescription.trim() || null,
        image_url: imageUrl,
        link_url: linkType === "restaurant" && selectedRestaurantId
          ? `/restaurant/${selectedRestaurantId}`
          : linkUrl.trim() || null,
        global_enabled: globalEnabled,
        target_countries: globalEnabled ? [] : selectedCountries,
        desired_start_date: desiredStartDate || null,
        desired_duration_months: desiredDuration,
        notes: notes.trim() || null,
      } as any);
      if (error) throw error;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["my-ad-requests"] });
      toast.success(t("merchant.adRequest.submitted"));
      setAdName("");
      setAdDescription("");
      setImageUrl("");
      setLinkUrl("");
      setLinkType("external");
      setSelectedRestaurantId("");
      setGlobalEnabled(false);
      setSelectedCountries([]);
      setDesiredStartDate("");
      setDesiredDuration(1);
      setNotes("");
    },
    onError: (err: any) => {
      toast.error(err.message || "Failed to submit");
    },
  });

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    if (file.size > 5 * 1024 * 1024) {
      toast.error(t("merchant.adRequest.fileTooLarge"));
      return;
    }
    setIsUploading(true);
    try {
      const ext = file.name.split('.').pop();
      const fileName = `ad-req-${Date.now()}-${Math.random().toString(36).slice(2)}.${ext}`;
      const { error: uploadError } = await supabase.storage.from('promo-images').upload(fileName, file);
      if (uploadError) throw uploadError;
      const { data: { publicUrl } } = supabase.storage.from('promo-images').getPublicUrl(fileName);
      setImageUrl(publicUrl);
      toast.success(t("merchant.adRequest.imageUploaded"));
    } catch (err: any) {
      toast.error(err.message || "Upload failed");
    } finally {
      setIsUploading(false);
    }
  };

  const toggleCountry = (code: string) => {
    setSelectedCountries(prev =>
      prev.includes(code) ? prev.filter(c => c !== code) : [...prev, code]
    );
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case "pending":
        return <Badge variant="secondary" className="gap-1"><Clock className="h-3 w-3" />{t("merchant.adRequest.statusPending")}</Badge>;
      case "approved":
        return <Badge className="gap-1 bg-primary"><CheckCircle className="h-3 w-3" />{t("merchant.adRequest.statusApproved")}</Badge>;
      case "rejected":
        return <Badge variant="destructive" className="gap-1"><XCircle className="h-3 w-3" />{t("merchant.adRequest.statusRejected")}</Badge>;
      default:
        return <Badge variant="outline">{status}</Badge>;
    }
  };

  return (
    <div className="container mx-auto px-4 py-6 max-w-4xl space-y-8">
      {/* Header / Introduction */}
      <div className="text-center space-y-3">
        <div className="inline-flex items-center justify-center w-14 h-14 rounded-2xl bg-primary/10">
          <Megaphone className="h-7 w-7 text-primary" />
        </div>
        <h1 className="text-2xl font-bold">{t("merchant.adRequest.title")}</h1>
        <p className="text-muted-foreground text-sm max-w-lg mx-auto">
          {t("merchant.adRequest.subtitle")}
        </p>
        <Badge variant="secondary" className="text-xs">
          <Gift className="h-3 w-3 mr-1" />
          {t("merchant.adRequest.firstMonthFree")}
        </Badge>
      </div>

      {/* Quick info cards */}
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
        {[
          { icon: MapPin, text: t("merchant.adRequest.countryTargeting") },
          { icon: Eye, text: t("merchant.adRequest.unclaimedStores") },
          { icon: Gift, text: t("merchant.adRequest.monthlyRenewal") },
        ].map((item, i) => (
          <Card key={i} className="border-border/50">
            <CardContent className="p-4 flex items-center gap-3">
              <item.icon className="h-4 w-4 text-primary shrink-0" />
              <span className="text-xs text-muted-foreground">{item.text}</span>
            </CardContent>
          </Card>
        ))}
      </div>

      <Separator />

      {/* Application Form */}
      <Card>
        <CardHeader>
          <CardTitle className="text-lg flex items-center gap-2">
            <Send className="h-5 w-5" />
            {t("merchant.adRequest.submitTitle")}
          </CardTitle>
        </CardHeader>
        <CardContent className="space-y-5">
          {/* Ad Name */}
          <div className="space-y-2">
            <Label>{t("merchant.adRequest.adName")} *</Label>
            <Input
              value={adName}
              onChange={e => setAdName(e.target.value)}
              placeholder={t("merchant.adRequest.adNamePlaceholder")}
              maxLength={100}
            />
          </div>

          {/* Ad Description */}
          <div className="space-y-2">
            <Label>{t("merchant.adRequest.adDescription")}</Label>
            <Textarea
              value={adDescription}
              onChange={e => setAdDescription(e.target.value)}
              placeholder={t("merchant.adRequest.adDescPlaceholder")}
              maxLength={500}
              rows={3}
            />
          </div>

          {/* Image Upload */}
          <div className="space-y-2">
            <Label>{t("merchant.adRequest.adImage")} *</Label>
            <p className="text-xs text-muted-foreground">
              {t("merchant.adRequest.imageHint")}
            </p>
            {imageUrl && (
              <div className="relative rounded-lg overflow-hidden border border-border">
                <img src={imageUrl} alt="Ad preview" className="w-full h-40 object-cover" />
                <Button
                  variant="destructive"
                  size="sm"
                  className="absolute top-2 right-2"
                  onClick={() => setImageUrl("")}
                >
                  <XCircle className="h-3 w-3" />
                </Button>
              </div>
            )}
            <div className="flex items-center gap-2">
              <Button variant="outline" size="sm" disabled={isUploading} asChild>
                <label className="cursor-pointer">
                  {isUploading ? <Loader2 className="h-4 w-4 animate-spin mr-1" /> : <Upload className="h-4 w-4 mr-1" />}
                  {t("merchant.adRequest.uploadImage")}
                  <input type="file" accept="image/*" className="hidden" onChange={handleImageUpload} />
                </label>
              </Button>
            </div>
          </div>

          {/* Link URL */}
          <div className="space-y-3">
            <Label>{t("merchant.adRequest.clickUrl")}</Label>
            <div className="flex gap-2">
              <button
                onClick={() => setLinkType("restaurant")}
                className={`flex-1 px-3 py-2 rounded-lg text-sm font-medium border transition-all ${
                  linkType === "restaurant"
                    ? "bg-primary text-primary-foreground border-primary"
                    : "bg-background border-border/60 hover:border-primary/40"
                }`}
              >
                {t("merchant.adRequest.myStore")}
              </button>
              <button
                onClick={() => setLinkType("external")}
                className={`flex-1 px-3 py-2 rounded-lg text-sm font-medium border transition-all ${
                  linkType === "external"
                    ? "bg-primary text-primary-foreground border-primary"
                    : "bg-background border-border/60 hover:border-primary/40"
                }`}
              >
                {t("merchant.adRequest.externalLink")}
              </button>
            </div>

            {linkType === "restaurant" ? (
              <div className="space-y-2">
                <Select value={selectedRestaurantId} onValueChange={setSelectedRestaurantId}>
                  <SelectTrigger>
                    <SelectValue placeholder={t("merchant.adRequest.selectStore")} />
                  </SelectTrigger>
                  <SelectContent>
                    {myRestaurants.map((r: any) => {
                      const localized = localizeRestaurant(r);
                      return (
                        <SelectItem key={r.id} value={r.id}>
                          {localized.name}
                        </SelectItem>
                      );
                    })}
                  </SelectContent>
                </Select>
                {myRestaurants.length === 0 && (
                  <p className="text-xs text-muted-foreground flex items-center gap-1">
                    <Info className="h-3 w-3" />
                    {t("merchant.adRequest.noStores")}
                  </p>
                )}
              </div>
            ) : (
              <div className="space-y-2">
                <Input
                  value={linkUrl}
                  onChange={e => setLinkUrl(e.target.value)}
                  placeholder="https://example.com"
                  maxLength={500}
                />
                <p className="text-xs text-muted-foreground flex items-center gap-1">
                  <Info className="h-3 w-3" />
                  {t("merchant.adRequest.enterFullUrl")}
                </p>
              </div>
            )}
          </div>

          <Separator />

          {/* Targeting */}
          <div className="space-y-3">
            <Label className="flex items-center gap-2">
              <Globe className="h-4 w-4" />
              {t("merchant.adRequest.targeting")}
            </Label>
            <div className="flex items-center gap-3">
              <Switch checked={globalEnabled} onCheckedChange={setGlobalEnabled} />
              <span className="text-sm">{t("merchant.adRequest.global")}</span>
            </div>
            {!globalEnabled && (
              <div className="flex flex-wrap gap-2">
                {COUNTRY_OPTIONS.map(c => (
                  <button
                    key={c.code}
                    onClick={() => toggleCountry(c.code)}
                    className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-all ${
                      selectedCountries.includes(c.code)
                        ? "bg-primary text-primary-foreground border-primary"
                        : "bg-background border-border/60 hover:border-primary/40"
                    }`}
                  >
                    {c.label}
                  </button>
                ))}
              </div>
            )}
          </div>

          <Separator />

          {/* Desired timing */}
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label>{t("merchant.adRequest.startDate")}</Label>
              <Input type="date" value={desiredStartDate} onChange={e => setDesiredStartDate(e.target.value)} />
            </div>
            <div className="space-y-2">
              <Label>{t("merchant.adRequest.durationMonths")}</Label>
              <Input
                type="number"
                min={1}
                max={24}
                value={desiredDuration}
                onChange={e => setDesiredDuration(Math.max(1, Math.min(24, parseInt(e.target.value) || 1)))}
              />
            </div>
          </div>

          {/* Notes */}
          <div className="space-y-2">
            <Label>{t("merchant.adRequest.notes")}</Label>
            <Textarea
              value={notes}
              onChange={e => setNotes(e.target.value)}
              placeholder={t("merchant.adRequest.notesPlaceholder")}
              maxLength={1000}
              rows={3}
            />
          </div>

          {/* Live Preview */}
          {(adName || imageUrl) && (
            <>
              <Separator />
              <div className="space-y-2">
                <Label className="flex items-center gap-2">
                  <Eye className="h-4 w-4" />
                  {t("merchant.adRequest.adPreview")}
                </Label>
                <div className="rounded-lg border border-border overflow-hidden bg-muted/30">
                  {imageUrl ? (
                    <img src={imageUrl} alt="Ad preview" className="w-full h-40 object-cover" />
                  ) : (
                    <div className="w-full h-40 flex items-center justify-center text-muted-foreground text-sm">
                      {t("merchant.adRequest.uploadAdImage")}
                    </div>
                  )}
                  <div className="p-3 space-y-1">
                    <p className="font-semibold text-sm">{adName || t("merchant.adRequest.adName")}</p>
                    {adDescription && <p className="text-xs text-muted-foreground line-clamp-2">{adDescription}</p>}
                    {(linkType === "restaurant" && selectedRestaurantId) || linkUrl ? (
                      <p className="text-xs text-primary flex items-center gap-1">
                        <ExternalLink className="h-3 w-3" />
                        {linkType === "restaurant" ? t("merchant.adRequest.linksToStore") : linkUrl}
                      </p>
                    ) : null}
                  </div>
                </div>
              </div>
            </>
          )}

          <Separator />

          {/* Submit */}
          <Button
            className="w-full"
            size="lg"
            onClick={() => submitRequest.mutate()}
            disabled={submitRequest.isPending || !adName.trim() || !imageUrl}
          >
            {submitRequest.isPending ? (
              <Loader2 className="h-4 w-4 animate-spin mr-2" />
            ) : (
              <Send className="h-4 w-4 mr-2" />
            )}
            {t("merchant.adRequest.submit")}
          </Button>
        </CardContent>
      </Card>

      {/* My Requests History */}
      {myRequests.length > 0 && (
        <>
          <Separator />
          <div className="space-y-4">
            <h2 className="text-lg font-semibold">{t("merchant.adRequest.myRequests")}</h2>
            <div className="space-y-3">
              {myRequests.map((req: any) => (
                <Card key={req.id} className="border-border/50">
                  <CardContent className="p-4">
                    <div className="flex items-start justify-between gap-3">
                      <div className="flex items-start gap-3 min-w-0">
                        {req.image_url && (
                          <img src={req.image_url} alt={req.ad_name} className="w-20 h-12 object-cover rounded shrink-0" />
                        )}
                        <div className="min-w-0">
                          <div className="font-medium text-sm truncate">{req.ad_name}</div>
                          <div className="text-xs text-muted-foreground mt-0.5">
                            {new Date(req.created_at).toLocaleDateString()}
                            {req.global_enabled
                              ? ` · ${t("merchant.adRequest.global")}`
                              : req.target_countries?.length
                                ? ` · ${req.target_countries.join(", ")}`
                                : ""}
                          </div>
                          {req.admin_notes && (
                            <p className="text-xs text-muted-foreground mt-1 italic">
                              {t("merchant.adRequest.adminNotes")}{req.admin_notes}
                            </p>
                          )}
                        </div>
                      </div>
                      {getStatusBadge(req.status)}
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          </div>
        </>
      )}

      {isLoading && (
        <div className="flex justify-center py-8">
          <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
        </div>
      )}
    </div>
  );
};

export default MerchantAdRequest;
